import createDebug from"debug";import{createReadStream,promises as fsPromises}from"fs";import NotFoundError from"./notfound.js";import NotModifiedError from"./notmodified.js";import{fileURLToPath}from"url";const debug=createDebug("get-uri:file");export const file=async({href:o},t={})=>{const{cache:e,flags:r="r",mode:i=438}=t;try{const a=fileURLToPath(o);debug("Normalized pathname: %o",a);const s=await fsPromises.open(a,r,i),f=await s.stat();if(e&&e.stat&&f&&isNotModified(e.stat,f))throw await s.close(),new NotModifiedError;const m=createReadStream(a,{autoClose:!0,...t,fd:s});return m.stat=f,m}catch(o){if("ENOENT"===o.code)throw new NotFoundError;throw o}};function isNotModified(o,t){return+o.mtime===+t.mtime}